noncompliant:
// Noncompliant: Explicit void parameter
void initializeSystem(void) {
    // Initialize system
}

// Another noncompliant example
int getCurrentTime(void) {
    return time(nullptr);
}

// Noncompliant in class method
class MyClass {
public:
    void reset(void) {
        // Reset object state
    }
};

compliant:
// Compliant: No explicit void parameter
void initializeSystem() {
    // Initialize system
}

// Another compliant example
int getCurrentTime() {
    return time(nullptr);
}

// Compliant in class method
class MyClass {
public:
    void reset() {
        // Reset object state
    }
};
